@app.route("/health", methods=["GET"])
def health():
    try:
        memcache.set("healthcheck", "ok", expire=5)
        cache_status = memcache.get("healthcheck")
        if isinstance(cache_status, bytes):
            cache_status = cache_status.decode("utf-8")
        return jsonify({
            "status": "ok",
            "memcached": cache_status == "ok",
            "timestamp": int(time.time())
        })
    except Exception as e:
        return jsonify({
            "status": "degraded",
            "memcached": False,
            "error": str(e)
        }), 500

